export function getRandomWord(length: number, isLevel1?: boolean): string {
  if (isLevel1) {
    const easyList = EASY_WORDS_LEVEL_1[length];
    if (easyList && easyList.length > 0) {
      const filteredEasyList = easyList.filter(word => word.trim().length === length);
      if (filteredEasyList.length > 0) {
        const word = filteredEasyList[Math.floor(Math.random() * filteredEasyList.length)];
        return turkishUpper(word);
      }
    }
  }

  const words = populerKelimeler[length] || [];
  const filteredWords = words.filter(word => word.trim().length === length);
  if (!filteredWords || filteredWords.length === 0) {
    const fallbackWords: { [key: number]: string[] } = {
      3: ['ana', 'arı', 'ara', 'bal', 'çay', 'dağ', 'iyi', 'kar', 'koç', 'şef', 'tek', 'tuz', 'yaz', 'yol', 'zor'],
      4: ['açık', 'adım', 'alan', 'altı'],
      5: ['kalem', 'kitap', 'büyük', 'yeşil'],
      6: ['adalet', 'akıllı', 'bardak', 'başarı'],
      7: ['arkadaş', 'hastane', 'merhaba'],
      8: ['belediye', 'güzellik', 'temizlik', 'öğretmen']
    };
    const list = (fallbackWords[length] || fallbackWords[5]).filter(word => word.trim().length === length);
    const finalWord = list.length > 0 ? list[Math.floor(Math.random() * list.length)] : 'SAVAŞ';
    return turkishUpper(finalWord);
  }
  const word = filteredWords[Math.floor(Math.random() * filteredWords.length)];
  return turkishUpper(word);
}

// Checks if a word exists in our curated list
export function isWordInCuratedList(word: string, length: number): boolean {
  const normalized = turkishLower(word);
  const list = CLEANED_TURKISH_WORDS[length] || [];
  return list.includes(normalized);
}

// Determines the daily word and length deterministically based on date with anti-bug validation
export function getDailyWordAndLength(): { word: string; length: number; dateStr: string } {
  const now = new Date();
  const year = now.getFullYear();
  const month = String(now.getMonth() + 1).padStart(2, '0');
  const day = String(now.getDate()).padStart(2, '0');
  const dateStr = `${year}-${month}-${day}`; // e.g. "2026-07-13"

  let hash = 0;
  for (let i = 0; i < dateStr.length; i++) {
    hash += dateStr.charCodeAt(i) * (i + 1);
  }

  // Length cycle: 3, 4, 5, 6, 7, 8 based on hash
  // Using modulo 6 gives values 0..5, so adding 3 gives 3, 4, 5, 6, 7, 8
  const length = 3 + (hash % 6);

  // Get words of this length from the popular list
  const list = populerKelimeler[length] || [];
  let selectedWord = '';

  const dictionary = COMMON_TURKISH_WORDS[length] || [];

  if (list.length > 0) {
    const startIndex = hash % list.length;
    // Iterate through the popular list deterministically to find a word that is definitely in the dictionary
    for (let i = 0; i < list.length; i++) {
      const candidate = list[(startIndex + i) % list.length];
      const trimmedCandidate = candidate.replace(/\r/g, '').replace(/\n/g, '').trim();
      if (trimmedCandidate.length === length) {
        const lowerCandidate = trimmedCandidate.toLocaleLowerCase('tr-TR');
        if (dictionary.includes(lowerCandidate) || dictionary.includes(trimmedCandidate)) {
          selectedWord = trimmedCandidate.toLocaleUpperCase('tr-TR');
          break;
        }
      }
    }
  }

  // Absolute fallback if no popular word is validated against the dictionary
  if (!selectedWord || selectedWord.length !== length) {
    const fallbackWords: { [key: number]: string } = {
      3: 'ARA',
      4: 'ALAN',
      5: 'KALEM',
      6: 'BARDAK',
      7: 'ARKADAŞ',
      8: 'ÖĞRETMEN'
    };
    selectedWord = fallbackWords[length] || 'KALEM';
  }

  return { word: selectedWord, length, dateStr };
}

