// Merge supplemental words into both COMMON_TURKISH_WORDS and CLEANED_TURKISH_WORDS
Object.keys(EXTRA_TURKISH_WORDS).forEach((keyStr) => {
  const key = parseInt(keyStr, 10);
  if (!COMMON_TURKISH_WORDS[key]) {
    COMMON_TURKISH_WORDS[key] = [];
  }
  if (!CLEANED_TURKISH_WORDS[key]) {
    CLEANED_TURKISH_WORDS[key] = [];
  }

  EXTRA_TURKISH_WORDS[key].forEach((word) => {
    const trimmed = word.replace(/\r/g, '').replace(/\n/g, '').trim();
    
    // Add to COMMON_TURKISH_WORDS if not already there
    if (!COMMON_TURKISH_WORDS[key].includes(trimmed)) {
      COMMON_TURKISH_WORDS[key].push(trimmed);
    }
    
    // Add to CLEANED_TURKISH_WORDS if not already there
    const lower = turkishLower(trimmed);
    if (!CLEANED_TURKISH_WORDS[key].includes(lower)) {
      CLEANED_TURKISH_WORDS[key].push(lower);
    }
  });
});

// Strict sanitization of all word lists to ensure words are filed under the correct length keys
for (let len = 3; len <= 8; len++) {
  if (COMMON_TURKISH_WORDS[len]) {
    COMMON_TURKISH_WORDS[len] = COMMON_TURKISH_WORDS[len].filter(
      (word) => word.replace(/\r/g, '').replace(/\n/g, '').trim().length === len
    );
  }
  if (CLEANED_TURKISH_WORDS[len]) {
    CLEANED_TURKISH_WORDS[len] = CLEANED_TURKISH_WORDS[len].filter(
      (word) => word.replace(/\r/g, '').replace(/\n/g, '').trim().length === len
    );
  }
  if (populerKelimeler[len]) {
    populerKelimeler[len] = populerKelimeler[len].filter(
      (word) => word.replace(/\r/g, '').replace(/\n/g, '').trim().length === len
    );
  }
}
